import sys
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)

    def insert(self, word):
        node = self
        for char in word:
            node = node.children[char]
        return True

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        self.root.insert(word)

        # Handle the insertion of the word
        return True

trie = Trie()
for i in range(int(sys.stdin.readline())):
