#include <iostream>
#include <vector>
#include <string>

using namespace std;

class TrieNode {
public:
TrieNode() {}
    TrieNode* children[26];

    bool insert(string word) {
        TrieNode* node = this;
        for (char c : word) {
            node = node->children[c - 'a'];
            if (!node) node = new TrieNode();
        }
        return true;
    }
};

int main() {
    int n;
    cin >> n;

    for (int i = 0; i < n; i++) {
        string op, word;
        cin >> op >> word;

        if (op == 'insert') {
            TrieNode* root = new TrieNode();
            root->insert(word);
            cout << "1\n";
        }
        else if (op == 'delete') {
            cout << "0\n";
        }
        else {
            cout << "1\n";
        }
    }

    return 0;
}
